#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>

typedef unsigned long long ULL;

#define MAX_N 8
#define MAX_M 8
#define MAX_HEIGHT 26

ULL memo[MAX_N][MAX_M][MAX_HEIGHT + 1];

ULL count_jumps(int n, int m, int sx, int sy, int fx, int fy, int height[MAX_N][MAX_M]) {
    if (sx < 0 || sx >= n || sy < 0 || sy >= m || height[sx][sy] == 0) return 0;
    if (sx == fx && sy == fy && height[sx][sy] == 1) return 1;
    if (memo[sx][sy][height[sx][sy]] != -1) return memo[sx][sy][height[sx][sy]];
    ULL count = 0;
    int dx[] = {1, 1, 2, 2, -1, -1, -2, -2};
    int dy[] = {2, -2, 1, -1, 2, -2, 1, -1};
    for (int i = 0; i < 8; i++) {
        int nx = sx + dx[i];
        int ny = sy + dy[i];
        if (nx >= 0 && nx < n && ny >= 0 && ny < m && height[nx][ny] > 0) {
            int new_height[MAX_N][MAX_M];
            memcpy(new_height, height, sizeof(new_height));
            new_height[sx][sy]--;
            count += count_jumps(n, m, nx, ny, fx, fy, new_height);
        }
    }
    memo[sx][sy][height[sx][sy]] = count;
    return count;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m, sx, sy, fx, fy;
        scanf("%d %d %d %d %d %d", &n, &m, &sx, &sy, &fx, &fy);
        sx--; sy--; fx--; fy--;
        int height[MAX_N][MAX_M];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                scanf("%d", &height[i][j]);
            }
        }
        memset(memo, -1, sizeof(memo));
        printf("%llu\n", count_jumps(n, m, sx, sy, fx, fy, height));
    }
    return 0;
}

