import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.io.PrintWriter;
import java.util.StringTokenizer;

public class Main {
    static final int MAX_N = 8;
    static final int MAX_M = 8;
    static final int MAX_HEIGHT = 26;

    static long[][][] memo = new long[MAX_N][MAX_M][MAX_HEIGHT + 1];

    static long count_jumps(int n, int m, int sx, int sy, int fx, int fy, int[][] height) {
        if (sx < 0 || sx >= n || sy < 0 || sy >= m || height[sx][sy] == 0) return 0;
        if (sx == fx && sy == fy && height[sx][sy] == 1) return 1;
        if (memo[sx][sy][height[sx][sy]] != -1) return memo[sx][sy][height[sx][sy]];
        long count = 0;
        int dx[] = {1, 1, 2, 2, -1, -1, -2, -2};
        int dy[] = {2, -2, 1, -1, 2, -2, 1, -1};
        for (int i = 0; i < 8; i++) {
            int nx = sx + dx[i];
            int ny = sy + dy[i];
            if (nx >= 0 && nx < n && ny >= 0 && ny < m && height[nx][ny] > 0) {
                int[][] new_height = new int[n][m];
                for (int j = 0; j < n; j++) {
                    System.arraycopy(height[j], 0, new_height[j], 0, m);
                }
                new_height[sx][sy]--;
                count += count_jumps(n, m, nx, ny, fx, fy, new_height);
            }
        }
        memo[sx][sy][height[sx][sy]] = count;
        return count;
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        PrintWriter pw = new PrintWriter(System.out);
        StringTokenizer st = new StringTokenizer(br.readLine());
        int t = Integer.parseInt(st.nextToken());
        while (t-- > 0) {
            st = new StringTokenizer(br.readLine());
            int n = Integer.parseInt(st.nextToken());
            int m = Integer.parseInt(st.nextToken());
            int sx = Integer.parseInt(st.nextToken()) - 1;
            int sy = Integer.parseInt(st.nextToken()) - 1;
            int fx = Integer.parseInt(st.nextToken()) - 1;
            int fy = Integer.parseInt(st.nextToken()) - 1;
            int[][] height = new int[n][m];
            for (int i = 0; i < n; i++) {
                st = new StringTokenizer(br.readLine());
                for (int j = 0; j < m; j++) {
                    height[i][j] = Integer.parseInt(st.nextToken());
                }
            }
            for (long[][] a : memo) {
                for (long[] b : a) {
                    java.util.Arrays.fill(b, -1);
                }
            }
            pw.println(count_jumps(n, m, sx, sy, fx, fy, height));
        }
        pw.close();
    }
}

